// Save game class
UCLASS()
class UMySaveGame : public USaveGame {
    GENERATED_BODY()
public:
    UPROPERTY()
    FVector PlayerLocation;

    UPROPERTY()
    float PlayerHealth;

    UPROPERTY()
    int32 PlayerLevel;

    UPROPERTY()
    TArray<FItemData> Inventory;

    UPROPERTY()
    TMap<FName, bool> CompletedQuests;
};

// Saving
void AMyGameMode::SaveGame() {
    UMySaveGame* Save = Cast<UMySaveGame>(
        UGameplayStatics::CreateSaveGameObject(UMySaveGame::StaticClass())
    );

    AMyCharacter* Player = Cast<AMyCharacter>(UGameplayStatics::GetPlayerCharacter(GetWorld(), 0));
    Save->PlayerLocation = Player->GetActorLocation();
    Save->PlayerHealth = Player->Health;
    Save->PlayerLevel = Player->Level;
    Save->Inventory = Player->Inventory;

    UGameplayStatics::SaveGameToSlot(Save, TEXT("Slot1"), 0);
}

// Loading
void AMyGameMode::LoadGame() {
    if (UGameplayStatics::DoesSaveGameExist(TEXT("Slot1"), 0)) {
        UMySaveGame* Save = Cast<UMySaveGame>(
            UGameplayStatics::LoadGameFromSlot(TEXT("Slot1"), 0)
        );
        // Apply loaded data to the player...
    }
}

// Async save
void AMyGameMode::AutoSave() {
    UMySaveGame* Save = PopulateSaveData();

    FAsyncSaveGameToSlotDelegate SaveDelegate;
    SaveDelegate.BindUObject(this, &AMyGameMode::OnSaveComplete);

    UGameplayStatics::AsyncSaveGameToSlot(Save, TEXT("AutoSave"), 0, SaveDelegate);
}

void AMyGameMode::OnSaveComplete(const FString& SlotName, int32 UserIndex, bool bSuccess) {
    if (bSuccess) {
        UE_LOG(LogTemp, Log, TEXT("Auto-save successful"));
    }
}

// Async load
void AMyGameMode::LoadGameAsync() {
    FAsyncLoadGameFromSlotDelegate LoadDelegate;
    LoadDelegate.BindUObject(this, &AMyGameMode::OnLoadComplete);

    UGameplayStatics::AsyncLoadGameFromSlot(TEXT("AutoSave"), 0, LoadDelegate);
}

void AMyGameMode::OnLoadComplete(const FString& SlotName, int32 UserIndex, USaveGame* SaveGame) {
    if (UMySaveGame* Save = Cast<UMySaveGame>(SaveGame)) {
        ApplySaveData(Save);
    }
}
